import React, { useState, useEffect } from "react";
import api from "../api/api";
import { Table, Button, Modal, Form } from "react-bootstrap";
import { FaPlus, FaEdit, FaTrash } from "react-icons/fa";

export default function Categorias() {
  const [categorias, setCategorias] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [categoriaId, setCategoriaId] = useState(null);
  
  // Datos del formulario
  const [nombre, setNombre] = useState("");
  const [descripcion, setDescripcion] = useState("");

  // 1. Obtener categorías al cargar
  useEffect(() => {
    fetchCategorias();
  }, []);

  const fetchCategorias = async () => {
    try {
      const res = await api.get("/categorias");
      setCategorias(res.data);
    } catch (error) {
      console.error("Error al obtener categorías:", error);
    }
  };

  // 2. Manejar Guardar / Actualizar
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editMode) {
        await api.put(`/categorias/${categoriaId}`, { nombre, descripcion });
      } else {
        await api.post("/categorias", { nombre, descripcion });
      }
      handleClose();
      fetchCategorias();
    } catch (error) {
      alert("Error al guardar la categoría");
    }
  };

  // 3. Manejar Eliminar
  const handleDelete = async (id) => {
    if (window.confirm("¿Estás seguro de eliminar esta categoría?")) {
      try {
        await api.delete(`/categorias/${id}`);
        fetchCategorias();
      } catch (error) {
        alert("No se pudo eliminar la categoría");
      }
    }
  };

  // 4. Funciones del Modal
  const handleShow = (cat = null) => {
    if (cat) {
      setEditMode(true);
      setCategoriaId(cat._id);
      setNombre(cat.nombre);
      setDescripcion(cat.descripcion);
    } else {
      setEditMode(false);
      setNombre("");
      setDescripcion("");
    }
    setShowModal(true);
  };

  const handleClose = () => {
    setShowModal(false);
    setNombre("");
    setDescripcion("");
  };

  return (
    <div className="container-fluid p-4">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h2 className="fw-bold text-dark">Gestión de Categorías</h2>
        <Button variant="primary" className="shadow-sm" onClick={() => handleShow()}>
          <FaPlus className="me-2" /> Nueva Categoría
        </Button>
      </div>

      <div className="card shadow-sm border-0">
        <div className="card-body p-0">
          <Table hover responsive className="mb-0">
            <thead className="bg-light">
              <tr>
                <th className="px-4 py-3">Nombre</th>
                <th className="px-4 py-3">Descripción</th>
                <th className="px-4 py-3 text-center">Acciones</th>
              </tr>
            </thead>
            <tbody>
              {categorias.map((cat) => (
                <tr key={cat._id} className="align-middle">
                  <td className="px-4 fw-bold text-secondary">{cat.nombre}</td>
                  <td className="px-4 text-muted">{cat.descripcion}</td>
                  <td className="px-4 text-center">
                    <Button variant="outline-warning" size="sm" className="me-2" onClick={() => handleShow(cat)}>
                      <FaEdit />
                    </Button>
                    <Button variant="outline-danger" size="sm" onClick={() => handleDelete(cat._id)}>
                      <FaTrash />
                    </Button>
                  </td>
                </tr>
              ))}
            </tbody>
          </Table>
        </div>
      </div>

      {/* Modal para Crear/Editar */}
      <Modal show={showModal} onHide={handleClose} centered>
        <Modal.Header closeButton>
          <Modal.Title>{editMode ? "Editar Categoría" : "Nueva Categoría"}</Modal.Title>
        </Modal.Header>
        <Form onSubmit={handleSubmit}>
          <Modal.Body>
            <Form.Group className="mb-3">
              <Form.Label className="fw-bold">Nombre</Form.Label>
              <Form.Control
                type="text"
                value={nombre}
                onChange={(e) => setNombre(e.target.value)}
                required
              />
            </Form.Group>
            <Form.Group className="mb-3">
              <Form.Label className="fw-bold">Descripción</Form.Label>
              <Form.Control
                as="textarea"
                rows={3}
                value={descripcion}
                onChange={(e) => setDescripcion(e.target.value)}
              />
            </Form.Group>
          </Modal.Body>
          <Modal.Footer>
            <Button variant="secondary" onClick={handleClose}>Cancelar</Button>
            <Button variant="primary" type="submit">
              {editMode ? "Actualizar" : "Guardar"}
            </Button>
          </Modal.Footer>
        </Form>
      </Modal>
    </div>
  );
}
